% --- Method of moments - One point quadrature - Scattering by a circular% cylinderclearclcepsilon0    = 8.85418781 * 1e-12;                                                   % --- Free-space dielectric permittivitymu0         = 4 * pi * 1e-7;                                                        % --- Free-space magnetic permeabilityzeta0       = sqrt(mu0 / epsilon0);                                                 % --- Free-space wave impendance c           = 1 / sqrt(epsilon0 * mu0);                                             % --- Wavespeed in vacuumf           = 3e8;                                                                  % --- Operating frequencyomega       = 2 * pi * f;                                                           % --- Operating angular frequencybeta        = omega / c;                                                            % --- Wavenumberlambda      = 2 * pi / beta;                                                        % --- Wavelengtha           = 3 * lambda;                                                           % --- Cylinder radiusNN          = ceil(2 * pi * a / (lambda / 10));                                     % --- Number of discretization intervals of the cylinder's contour%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%% DISCRETIZATION OF THE CYLINDER SURFACE %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%t           = (0 : NN - 1) / NN * 2 * pi;                                           % --- Angular discretization of the circular cylinder surfacex           = a * cos(t);y           = a * sin(t);z           = a * exp(1i * t);                                                      % --- Discretization points (extremals of the segments)% --- Matching points at midpointsxp          = 0.5 * (x(1 : NN) + [x(2 : NN), x(1)]);yp          = 0.5 * (y(1 : NN) + [y(2 : NN), y(1)]);zp          = 0.5 * (z(1 : NN) + [z(2 : NN), z(1)]);[Xp, Yp]    = meshgrid(xp, yp);%%%%%%%%%%%%%%%%%%%%%%%% COEFFICIENTS MATRIX %%%%%%%%%%%%%%%%%%%%%%%%% panels:dz = diff([z,z(1)]);% lengthsph = abs(dz);2*pi/beta/ph(1),% unit normals - outward, points numbered anti-clockwise !pn = -i*dz./ph;% point-to-point vectorsRmn = ones(NN,1)*zp - (zp.')*ones(1,NN);% distances - we'll replace the diagonal later, just to avoid besselh(0)d = abs(Rmn) + eye(NN);% --- z, ki, beta is only input to the rest of the programgamma = 0.5772156649;% construct matrix%  Ge % Non-diagonal part of G% Greens function is 1/(4i) besselh(kr)o4i = -0.25*1i;Ge = o4i*besselh(0, 2, beta * d); return% diagonal% from maple: % 2*int(convert(series(HankelH2(0,x),x=0,2),polynom),x=0..h/2);I   = i;Pi  = pi;% first Geh = beta*ph;dGe = o4i*diag(h.*(Pi+2*I*log(4./h)+2*I-2*I*gamma)/Pi/beta./ph);% replace diagonal ...Ge  = Ge - diag(diag(Ge)) + dGe;Ei          = exp(-1i * beta * real(zp));                                           % --- Impinging wave% the unknowns are panel lengths * sources - % no h-scaling in matrix !% solvetmp = -Ge \ (Ei.');u = tmp(1:NN)./ph';% plotfigure(1);plot(t + 0.5*(t(2)-t(1)),abs(u),'k');% plot(t, abs(v),'b');pause% ... and visualize on polar evaluation gridRex = 10;nfi = 30;nr  = 30;t  = (0:nfi-1)*pi/(nfi-1);ni  = 5;r   = [linspace(0,0.95*a,ni),...	   linspace(1.05*a,Rex,nr-ni)]';nr   = length(r);zvis = r*exp(i*t); x = real(zvis); y = imag(zvis);Z    = zvis(:); N = length(Z);% point-to-point vectorsZtozm = ones(N,1)*zp - Z*ones(1,NN);% do this in blocks to avoid large matricesnbl = 30;nrows = floor(N/nbl);N - nrows*nblfor ibl = 1:nbl+1,	ibl,   nor = nrows;   if ibl==nbl+1	  nor = N - nrows*nbl;	  if nor == 0		 break	  end   end   ztoz = Ztozm((ibl-1)*nrows+1:(ibl-1)*nrows+nor,:);% distances   d = abs(ztoz);% G   Ge = o4i*besselh(0,2,beta*d );    Eext((ibl-1)*nrows+1:(ibl-1)*nrows+nor) = Ge*(u.*ph');endfigure(2);subplot(221); surf(x,y,real(reshape(Eext,nr,nfi)));axis equal; view(2); shading interp, title('Re Ext'); caxis([-2 2]);subplot(222); surf(x,y,abs(reshape(Eext,nr,nfi)));axis equal; view(2); shading interp, title('Abs Ext'); caxis([-2 2]);figure(3)Eext = Eext.'; Einc = exp(i*beta*x); Epl  = reshape(Eext + Einc(:),nr,nfi);indi = find(abs(Z) < a);Epl(indi) = 0;surf(x,y,real(Epl)); axis equal; view(2); shading interp